parameters.jsCode:
const item = $input.first();

let text = (item.json.data || item.json.text || item.json.content || '')
  .replace(/\s+/g, ' ')
  .trim();

const filename = item.json.filename || 'kb.txt';
const file_type = item.json.file_type || 'txt';

if (!text || text.length < 200) {
  throw new Error('Слишком короткий текст: ' + text.length);
}

text = text.replace(/[\u0000-\u001F\u007F]/g, '');

const CHUNK_SIZE = 800;
const OVERLAP = 80;
const MAX_CHUNKS = 50;
const MIN_STEP = 400;

const chunks = [];
let i = 0;
let iter = 0;

while (i < text.length && chunks.length < MAX_CHUNKS) {
  iter++;
  if (iter > 200) throw new Error('Loop guard: ' + iter);

  let end = Math.min(i + CHUNK_SIZE, text.length);

  if (end < text.length) {
    const lastDot = text.lastIndexOf('.', end);
    const lastSp = text.lastIndexOf(' ', end);
    const cut = Math.max(lastDot, lastSp);
    if (cut > i + MIN_STEP) end = cut + 1;
  }

  const piece = text.slice(i, end).trim();

  if (piece.length >= 80 && /[а-яА-Яa-zA-Z0-9]/.test(piece)) {
    chunks.push(piece);
  }

  const nextI = end - OVERLAP;
  i = (nextI > i) ? nextI : (i + MIN_STEP);

  if (end >= text.length) break;
}

if (chunks.length === 0) throw new Error('Нет валидных чанков');

return chunks.map((content, idx) => ({
  json: {
    content,
    chunk_index: idx,
    total_chunks: chunks.length,
    filename,
    file_type
  }
}));

const docId = $('Insert Document Record1').first().json.id;
const chunks = $('Chunk Text1').all();
return chunks.map(c => ({
  json: { ...c.json, document_id: docId }
}));

